module design_1_tri_mode_ethernet_mac_0_1_tx_clk_gen
   (tx_gmii_mii_clk,
    mii_tx_clk,
    speedis10100,
    gtx_clk);
  output tx_gmii_mii_clk;
  input mii_tx_clk;
  input speedis10100;
  input gtx_clk;

  wire gtx_clk;
  wire mii_tx_clk;
  wire mii_tx_clk_ibuf;
  wire speedis10100;
  wire tx_gmii_mii_clk;

  (* BOX_TYPE = "PRIMITIVE" *) 
  (* XILINX_LEGACY_PRIM = "BUFGMUX" *) 
  (* XILINX_TRANSFORM_PINMAP = "S:CE1,CE0 VCC:IGNORE1,IGNORE0,S1,S0" *) 
  BUFGCTRL #(
    .INIT_OUT(0),
    .IS_CE0_INVERTED(1'b1),
    .PRESELECT_I0("TRUE"),
    .PRESELECT_I1("FALSE"),
    .SIM_DEVICE("ULTRASCALE_PLUS")) 
    BUFGMUX_SPEED_CLK
       (.CE0(speedis10100),
        .CE1(speedis10100),
        .I0(gtx_clk),
        .I1(mii_tx_clk_ibuf),
        .IGNORE0(1'b1),
        .IGNORE1(1'b1),
        .O(tx_gmii_mii_clk),
        .S0(1'b1),
        .S1(1'b1));
