  (* CAPACITANCE = "DONT_CARE" *) 
  (* IBUF_DELAY_VALUE = "0" *) 
  (* IFD_DELAY_VALUE = "AUTO" *) 
  IBUF #(
    .IOSTANDARD("DEFAULT")) 
    mii_tx_clk_ibuf_i
       (.I(mii_tx_clk),
        .O(mii_tx_clk_ibuf));
endmodule

